{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → found (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on restricted → not available (no throw!)");
}

public record Person(string Name, int Age);

